record.field:
for line in record:
    if line.x_end_date and line.x_end_date < line.x_start_date: raise UserError("End Date must be empty or after Start Date.")
    domain = [('id', '!=', line.id), ('x_property_id', '=', line.x_property_id.id), ('x_type', '=', line.x_type), ('x_start_date', '!=', False), '|', ('x_end_date', '=', False), ('x_end_date', '>=', line.x_start_date)]
    if line.x_end_date: domain.append(('x_start_date', '<=', line.x_end_date))
    if env['x_stake_holder'].search_count(domain, limit=1): raise UserError("Stakeholder dates cannot overlap for the same property. Ensure that periods do not overlap.")

plan = env['account.analytic.plan'].search([('x_is_a_property_plan', '=', True)], limit=1)
for line in records:
    if (partner := line.x_stake_holder) and not env['account.analytic.account'].search_count([('x_property', '=', line.x_property_id.id), ('partner_id', '=', partner.id), ('x_type', '=', line.x_type)]):
        line['x_account'] = env['account.analytic.account'].create({
            'name': '[' + str(line.x_type) + '] ' + line.x_property_id.x_name,
            'plan_id': plan.id,
            'x_property': line.x_property_id.id,
            'partner_id': partner.id,
            'x_stake_holder_line': line.id,
            'company_id': partner.company_id.id,
            'x_type': line.x_type,
        }).id
